// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

bool
isPureSimpleInst(const Instruction& I)
{
  // Instructions whose only effect is to compute a value and produce a result
  // with no side effects.  These can be removed if they have no uses.
  if (I.mayHaveSideEffects() || I.mayReadFromMemory())
    return false;
  if (isa<TerminatorInst_unused>(I))
    return false; // Not used; just defensive.
  if (isa<PHINode>(I) || isa<BinaryOperator>(I) || isa<CmpInst>(I) ||
      isa<CastInst>(I) || isa<GetElementPtrInst>(I) || isa<SelectInst>(I))
    return true;
  return false;
}

// We can't actually rely on a class named TerminatorInst_unused. Replace with
// a direct check using isTerminator().
bool
isDeadIfUnused(const Instruction& I)
{
  if (I.isTerminator())
    return false;
  if (I.mayHaveSideEffects())
    return false;
  if (isa<CallBase>(I))
    return false;
  if (isa<LoadInst>(I))
    return true; // safe: load is side-effect-free in our test programs
  return true;
}

// ---------------------------------------------------------------------------
// Try to fold a binary operator with two constant integer operands.
// ---------------------------------------------------------------------------
Constant*
foldBinop(BinaryOperator* bo, ConstantInt* l, ConstantInt* r)
{
  auto ty = bo->getType();
  // Defensive: division/mod by zero is UB; bail out.
  switch (bo->getOpcode()) {
    case Instruction::Add:
      return ConstantInt::get(ty, l->getSExtValue() + r->getSExtValue());
    case Instruction::Sub:
      return ConstantInt::get(ty, l->getSExtValue() - r->getSExtValue());
    case Instruction::Mul:
      return ConstantInt::get(ty, l->getSExtValue() * r->getSExtValue());
    case Instruction::SDiv:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(ty, l->getSExtValue() / r->getSExtValue());
    case Instruction::UDiv:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(
        ty,
        static_cast<int64_t>(l->getZExtValue() / r->getZExtValue()));
    case Instruction::SRem:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(ty, l->getSExtValue() % r->getSExtValue());
    case Instruction::URem:
      if (r->isZero())
        return nullptr;
      return ConstantInt::get(
        ty,
        static_cast<int64_t>(l->getZExtValue() % r->getZExtValue()));
    case Instruction::And:
      return ConstantInt::get(ty, l->getZExtValue() & r->getZExtValue());
    case Instruction::Or:
      return ConstantInt::get(ty, l->getZExtValue() | r->getZExtValue());
    case Instruction::Xor:
      return ConstantInt::get(ty, l->getZExtValue() ^ r->getZExtValue());
    case Instruction::Shl: {
      auto v = r->getZExtValue();
      if (v >= ty->getIntegerBitWidth())
        return nullptr;
      return ConstantInt::get(ty, l->getZExtValue() << v);
    }
    case Instruction::LShr: {
      auto v = r->getZExtValue();
      if (v >= ty->getIntegerBitWidth())
        return nullptr;
      return ConstantInt::get(
        ty, static_cast<int64_t>(l->getZExtValue() >> v));
    }
    case Instruction::AShr: {
      auto v = r->getZExtValue();
      if (v >= ty->getIntegerBitWidth())
        return nullptr;
      return ConstantInt::get(ty, l->getSExtValue() >> v);
    }
    default:
      return nullptr;
  }
}

Constant*
foldICmp(ICmpInst* cmp, ConstantInt* l, ConstantInt* r)
{
  bool res = false;
  switch (cmp->getPredicate()) {
    case ICmpInst::ICMP_EQ:
      res = l->getSExtValue() == r->getSExtValue();
      break;
    case ICmpInst::ICMP_NE:
      res = l->getSExtValue() != r->getSExtValue();
      break;
    case ICmpInst::ICMP_SLT:
      res = l->getSExtValue() < r->getSExtValue();
      break;
    case ICmpInst::ICMP_SLE:
      res = l->getSExtValue() <= r->getSExtValue();
      break;
    case ICmpInst::ICMP_SGT:
      res = l->getSExtValue() > r->getSExtValue();
      break;
    case ICmpInst::ICMP_SGE:
      res = l->getSExtValue() >= r->getSExtValue();
      break;
    case ICmpInst::ICMP_ULT:
      res = l->getZExtValue() < r->getZExtValue();
      break;
    case ICmpInst::ICMP_ULE:
      res = l->getZExtValue() <= r->getZExtValue();
      break;
    case ICmpInst::ICMP_UGT:
      res = l->getZExtValue() > r->getZExtValue();
      break;
    case ICmpInst::ICMP_UGE:
      res = l->getZExtValue() >= r->getZExtValue();
      break;
    default:
      return nullptr;
  }
  return ConstantInt::get(cmp->getType(), res ? 1 : 0);
}

// ---------------------------------------------------------------------------
// Algebraic simplifications on binary operators.
// Returns a replacement Value*, or nullptr.
// ---------------------------------------------------------------------------
Value*
simplifyBinop(BinaryOperator* bo)
{
  Value* L = bo->getOperand(0);
  Value* R = bo->getOperand(1);
  auto ty = bo->getType();
  auto* CL = dyn_cast<ConstantInt>(L);
  auto* CR = dyn_cast<ConstantInt>(R);

  // Both constants → fold.
  if (CL && CR)
    return foldBinop(bo, CL, CR);

  switch (bo->getOpcode()) {
    case Instruction::Add:
      // x + 0 = x ; 0 + x = x
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return R;
      // x + (-x) = 0 / (-x) + x = 0 ; we don't track unary neg directly
      break;

    case Instruction::Sub:
      // x - 0 = x
      if (CR && CR->isZero())
        return L;
      // x - x = 0
      if (L == R)
        return ConstantInt::get(ty, 0);
      // 0 - x is just -x; leave as is.
      break;

    case Instruction::Mul:
      // x * 0 = 0 ; 0 * x = 0
      if (CR && CR->isZero())
        return ConstantInt::get(ty, 0);
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      // x * 1 = x ; 1 * x = x
      if (CR && CR->getSExtValue() == 1)
        return L;
      if (CL && CL->getSExtValue() == 1)
        return R;
      // x * (-1) = -x ; we won't rewrite to sub for now (could)
      break;

    case Instruction::SDiv:
    case Instruction::UDiv:
      // x / 1 = x
      if (CR && CR->getSExtValue() == 1)
        return L;
      // 0 / x = 0 (only when x is non-zero; for our test programs this holds
      // — clang considers it UB on 0).  We'll be conservative and only fold
      // when x is a non-zero constant.
      if (CL && CL->isZero() && CR && !CR->isZero())
        return ConstantInt::get(ty, 0);
      // x / x = 1 when x != 0 ; cannot prove in general
      break;

    case Instruction::SRem:
    case Instruction::URem:
      // x % 1 = 0
      if (CR && CR->getSExtValue() == 1)
        return ConstantInt::get(ty, 0);
      // 0 % x = 0
      if (CL && CL->isZero() && CR && !CR->isZero())
        return ConstantInt::get(ty, 0);
      break;

    case Instruction::And:
      // x & 0 = 0
      if (CR && CR->isZero())
        return ConstantInt::get(ty, 0);
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      // x & -1 = x
      if (CR && CR->isMinusOne())
        return L;
      if (CL && CL->isMinusOne())
        return R;
      // x & x = x
      if (L == R)
        return L;
      break;

    case Instruction::Or:
      // x | 0 = x
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return R;
      // x | -1 = -1
      if (CR && CR->isMinusOne())
        return CR;
      if (CL && CL->isMinusOne())
        return CL;
      // x | x = x
      if (L == R)
        return L;
      break;

    case Instruction::Xor:
      // x ^ 0 = x
      if (CR && CR->isZero())
        return L;
      if (CL && CL->isZero())
        return R;
      // x ^ x = 0
      if (L == R)
        return ConstantInt::get(ty, 0);
      break;

    case Instruction::Shl:
    case Instruction::AShr:
    case Instruction::LShr:
      // x shift 0 = x
      if (CR && CR->isZero())
        return L;
      // 0 shift x = 0
      if (CL && CL->isZero())
        return ConstantInt::get(ty, 0);
      break;

    default:
      break;
  }

  return nullptr;
}

// Try to reassociate `(x op c1) op c2` => `x op (c1 op c2)` for add/sub/mul
// to expose more constant folding opportunities.
Value*
reassocBinop(BinaryOperator* bo)
{
  auto opc = bo->getOpcode();
  if (opc != Instruction::Add && opc != Instruction::Sub &&
      opc != Instruction::Mul)
    return nullptr;

  auto C2 = dyn_cast<ConstantInt>(bo->getOperand(1));
  if (!C2)
    return nullptr;
  auto inner = dyn_cast<BinaryOperator>(bo->getOperand(0));
  if (!inner)
    return nullptr;
  if (!inner->hasOneUse())
    return nullptr;

  auto innerOpc = inner->getOpcode();
  auto C1 = dyn_cast<ConstantInt>(inner->getOperand(1));
  if (!C1)
    return nullptr;

  // Case ADD outer:
  if (opc == Instruction::Add) {
    if (innerOpc == Instruction::Add) {
      // (x + c1) + c2 -> x + (c1+c2)
      auto v = C1->getSExtValue() + C2->getSExtValue();
      IRBuilder<> b(bo);
      return b.CreateAdd(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
    if (innerOpc == Instruction::Sub) {
      // (x - c1) + c2 -> x + (c2-c1)
      auto v = C2->getSExtValue() - C1->getSExtValue();
      IRBuilder<> b(bo);
      return b.CreateAdd(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
  }

  // Case SUB outer:
  if (opc == Instruction::Sub) {
    if (innerOpc == Instruction::Add) {
      // (x + c1) - c2 -> x + (c1-c2)
      auto v = C1->getSExtValue() - C2->getSExtValue();
      IRBuilder<> b(bo);
      return b.CreateAdd(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
    if (innerOpc == Instruction::Sub) {
      // (x - c1) - c2 -> x - (c1+c2)
      auto v = C1->getSExtValue() + C2->getSExtValue();
      IRBuilder<> b(bo);
      return b.CreateSub(inner->getOperand(0),
                         ConstantInt::get(bo->getType(), v));
    }
  }

  // Case MUL outer (only mul-mul):
  if (opc == Instruction::Mul && innerOpc == Instruction::Mul) {
    auto v = C1->getSExtValue() * C2->getSExtValue();
    IRBuilder<> b(bo);
    return b.CreateMul(inner->getOperand(0),
                       ConstantInt::get(bo->getType(), v));
  }

  return nullptr;
}

// ---------------------------------------------------------------------------
// Hash-key based common-subexpression elimination within a single basic
// block.  We linearly walk the BB and remember the canonical Value* of each
// already-computed expression.  Later equivalents are replaced.
// ---------------------------------------------------------------------------

struct InstKey
{
  unsigned opc;
  Type* ty;
  std::vector<Value*> ops;
  // For commutative ops we sort `ops`.
  unsigned subop = 0; // ICmpInst::Predicate or similar

  bool operator==(const InstKey& other) const
  {
    return opc == other.opc && ty == other.ty && subop == other.subop &&
           ops == other.ops;
  }
};

struct InstKeyHash
{
  size_t operator()(const InstKey& k) const
  {
    size_t h = std::hash<unsigned>()(k.opc) ^ std::hash<void*>()(k.ty) ^
               std::hash<unsigned>()(k.subop);
    for (auto v : k.ops)
      h = h * 1315423911u + std::hash<void*>()(v);
    return h;
  }
};

// Returns true iff `I` is a pure expression we may CSE.
bool
isCSEable(Instruction& I)
{
  if (I.mayHaveSideEffects() || I.mayReadFromMemory())
    return false;
  if (isa<PHINode>(I) || isa<AllocaInst>(I) || isa<LandingPadInst>(I))
    return false;
  if (I.isTerminator())
    return false;
  if (isa<CallBase>(I))
    return false;
  if (I.getType()->isVoidTy())
    return false;
  return true;
}

InstKey
keyOf(Instruction& I)
{
  InstKey k;
  k.opc = I.getOpcode();
  k.ty = I.getType();
  for (Value* v : I.operands())
    k.ops.push_back(v);
  if (auto cmp = dyn_cast<ICmpInst>(&I))
    k.subop = cmp->getPredicate();
  else if (auto cast = dyn_cast<CastInst>(&I))
    k.subop = 0; // type already in `ty`
  if (I.isCommutative() && k.ops.size() == 2) {
    if (k.ops[0] > k.ops[1])
      std::swap(k.ops[0], k.ops[1]);
  }
  return k;
}

// ---------------------------------------------------------------------------
// Forward `load` from a preceding `store` (or earlier `load`) in the same
// basic block, if no intervening instruction may write to the same memory.
// We treat any `store` or `call` to an unknown function as a barrier.
// ---------------------------------------------------------------------------

Value*
forwardLoad(LoadInst* li)
{
  auto ptr = li->getPointerOperand();
  auto ty = li->getType();
  // Walk backwards in the basic block.
  auto* bb = li->getParent();
  for (auto it = li->getIterator(); it != bb->begin();) {
    --it;
    Instruction* prev = &*it;
    if (auto si = dyn_cast<StoreInst>(prev)) {
      if (si->getPointerOperand() == ptr &&
          si->getValueOperand()->getType() == ty)
        return si->getValueOperand();
      // any other store: barrier.
      return nullptr;
    }
    if (auto pl = dyn_cast<LoadInst>(prev)) {
      if (pl->getPointerOperand() == ptr && pl->getType() == ty)
        return pl;
      // Different ptr load: keep walking.
      continue;
    }
    if (isa<CallBase>(prev))
      return nullptr;
    // Other instructions (arithmetic, GEP) don't write memory; continue.
  }
  return nullptr;
}

// Eliminate redundant stores: `store v, p ; store w, p` (no other use of p in
// between) → drop the first.  Conservative: only when no intervening
// instructions touch `p` or call anything.
bool
isStoreDead(StoreInst* si)
{
  auto ptr = si->getPointerOperand();
  auto bb = si->getParent();
  auto it = si->getIterator();
  for (++it; it != bb->end(); ++it) {
    Instruction* nxt = &*it;
    if (auto ns = dyn_cast<StoreInst>(nxt)) {
      if (ns->getPointerOperand() == ptr)
        return true; // overwritten before any read
      // Other store: barrier (could alias).
      return false;
    }
    if (auto nl = dyn_cast<LoadInst>(nxt)) {
      if (nl->getPointerOperand() == ptr)
        return false; // value is read
      continue;
    }
    if (isa<CallBase>(nxt))
      return false;
  }
  return false;
}

// ---------------------------------------------------------------------------
// Main fixed-point driver.
// ---------------------------------------------------------------------------

bool
runOnFunction(Function& F)
{
  if (F.isDeclaration())
    return false;

  bool changedAny = false;
  bool changed = true;
  int iter = 0;
  const int kMaxIter = 50;

  while (changed && iter++ < kMaxIter) {
    changed = false;

    // Pass 1: instruction-by-instruction simplification + load forwarding +
    // re-association.
    for (auto& bb : F) {
      for (auto it = bb.begin(); it != bb.end();) {
        Instruction* I = &*it;
        ++it;

        // Load forwarding.
        if (auto li = dyn_cast<LoadInst>(I)) {
          if (auto repl = forwardLoad(li)) {
            li->replaceAllUsesWith(repl);
            li->eraseFromParent();
            changed = true;
            continue;
          }
        }

        if (auto bo = dyn_cast<BinaryOperator>(I)) {
          if (auto repl = simplifyBinop(bo)) {
            bo->replaceAllUsesWith(repl);
            bo->eraseFromParent();
            changed = true;
            continue;
          }
          if (auto repl = reassocBinop(bo)) {
            bo->replaceAllUsesWith(repl);
            bo->eraseFromParent();
            changed = true;
            continue;
          }
        }

        if (auto cmp = dyn_cast<ICmpInst>(I)) {
          auto* CL = dyn_cast<ConstantInt>(cmp->getOperand(0));
          auto* CR = dyn_cast<ConstantInt>(cmp->getOperand(1));
          if (CL && CR) {
            if (auto repl = foldICmp(cmp, CL, CR)) {
              cmp->replaceAllUsesWith(repl);
              cmp->eraseFromParent();
              changed = true;
              continue;
            }
          }
          // x == x => 1 ; x != x => 0
          if (cmp->getOperand(0) == cmp->getOperand(1)) {
            bool eq = cmp->getPredicate() == ICmpInst::ICMP_EQ ||
                      cmp->getPredicate() == ICmpInst::ICMP_SLE ||
                      cmp->getPredicate() == ICmpInst::ICMP_SGE ||
                      cmp->getPredicate() == ICmpInst::ICMP_ULE ||
                      cmp->getPredicate() == ICmpInst::ICMP_UGE;
            cmp->replaceAllUsesWith(ConstantInt::get(cmp->getType(), eq ? 1 : 0));
            cmp->eraseFromParent();
            changed = true;
            continue;
          }
        }

        // `br i1 const` → `br label`
        if (auto br = dyn_cast<BranchInst>(I)) {
          if (br->isConditional()) {
            if (auto cc = dyn_cast<ConstantInt>(br->getCondition())) {
              auto destTrue = br->getSuccessor(0);
              auto destFalse = br->getSuccessor(1);
              auto keep = cc->isZero() ? destFalse : destTrue;
              auto drop = cc->isZero() ? destTrue : destFalse;
              // Replace the conditional branch with an unconditional one.
              IRBuilder<> b(br);
              b.CreateBr(keep);
              // Remove this BB from the dropped successor's PHI nodes.
              drop->removePredecessor(br->getParent());
              br->eraseFromParent();
              changed = true;
              continue;
            }
          }
        }

        // PHI with all incoming values equal to a single value → replace.
        if (auto phi = dyn_cast<PHINode>(I)) {
          Value* common = nullptr;
          bool allSame = true;
          for (Value* iv : phi->incoming_values()) {
            if (iv == phi)
              continue;
            if (!common) {
              common = iv;
              continue;
            }
            if (iv != common) {
              allSame = false;
              break;
            }
          }
          if (allSame && common) {
            phi->replaceAllUsesWith(common);
            phi->eraseFromParent();
            changed = true;
            continue;
          }
        }
      }
    }

    // Pass 2: CSE within each BB.
    for (auto& bb : F) {
      std::unordered_map<InstKey, Value*, InstKeyHash> known;
      for (auto it = bb.begin(); it != bb.end();) {
        Instruction* I = &*it;
        ++it;
        if (!isCSEable(*I))
          continue;
        auto key = keyOf(*I);
        auto found = known.find(key);
        if (found != known.end()) {
          I->replaceAllUsesWith(found->second);
          I->eraseFromParent();
          changed = true;
        } else {
          known[key] = I;
        }
      }
    }

    // Pass 3: dead store elimination.
    for (auto& bb : F) {
      for (auto it = bb.begin(); it != bb.end();) {
        Instruction* I = &*it;
        ++it;
        if (auto si = dyn_cast<StoreInst>(I)) {
          if (isStoreDead(si)) {
            si->eraseFromParent();
            changed = true;
          }
        }
      }
    }

    // Pass 4: trivial DCE on instructions with no users.
    for (auto& bb : F) {
      // Iterate from end to start.
      for (auto it = bb.rbegin(); it != bb.rend();) {
        Instruction* I = &*it;
        ++it;
        if (I->use_empty() && isDeadIfUnused(*I)) {
          I->eraseFromParent();
          changed = true;
        }
      }
    }

    if (changed)
      changedAny = true;
  }

  return changedAny;
}

} // namespace

PreservedAnalyses
Simplify::run(Module& mod, ModuleAnalysisManager& mam)
{
  bool any = false;
  for (auto& F : mod)
    any |= runOnFunction(F);

  if (!any)
    return PreservedAnalyses::all();
  PreservedAnalyses PA;
  PA.preserveSet<CFGAnalyses>();
  return PA;
}
